commands.examples:
@echo off
rem === Variabel ===
set NAME=John
set /a AGE=25+5
set /p INPUT=Masukkan nama: 

echo Nama: %NAME%, Umur: %AGE%

rem === Kondisi ===
if exist C:\Data (
    echo Folder ditemukan
) else (
    echo Folder tidak ada
    mkdir C:\Data
)

if /i "%INPUT%"=="admin" (
    echo Selamat datang, Admin!
) else (
    echo Selamat datang, %INPUT%!
)

rem === Aritmatika ===
set /a RESULT=10*5+3
echo Hasil: %RESULT%

@echo off
rem === Loop file ===
for %%f in (*.txt) do echo File: %%f

rem === Loop angka 1-10 ===
for /l %%i in (1,1,10) do echo Nomor: %%i

rem === Loop rekursif ===
for /r C:\Data %%f in (*.log) do del "%%f"

rem === Loop dari output perintah ===
for /f "tokens=1,2" %%a in ('tasklist /nh') do (
    echo Proses: %%a, PID: %%b
)

rem === Loop dari file ===
for /f "tokens=*" %%line in (data.txt) do (
    echo %%line
)

# === Script dasar ===
param(
    [string]$Name = "World",
    [int]$Count = 1
)

function Say-Hello {
    param([string]$To)
    Write-Host "Hello, $To!" -ForegroundColor Green
}

for ($i = 0; $i -lt $Count; $i++) {
    Say-Hello -To $Name
}

# === Array & Hashtable ===
$fruits = @("Apple", "Banana", "Cherry")
$config = @{
    Server = "localhost"
    Port = 8080
    Debug = $true
}

foreach ($fruit in $fruits) {
    Write-Host $fruit
}

$config.GetEnumerator() | ForEach-Object {
    Write-Host "$($_.Key) = $($_.Value)"
}

# === Kondisional ===
$os = (Get-CimInstance Win32_OperatingSystem).Caption
if ($os -like "*Windows 11*") {
    Write-Host "Windows 11"
} elseif ($os -like "*Windows 10*") {
    Write-Host "Windows 10"
} else {
    Write-Host "OS lain: $os"
}

# === Switch ===
switch ($dayOfWeek) {
    'Monday'    { 'Senin' }
    'Tuesday'   { 'Selasa' }
    default     { 'Hari lain' }
}

# === Error Handling ===
try {
    $content = Get-Content "nofile.txt" -ErrorAction Stop
    Write-Host "Berhasil dibaca"
} catch [System.IO.FileNotFoundException] {
    Write-Host "File tidak ditemukan: $($_.Exception.Message)"
} catch {
    Write-Host "Error: $($_.Exception.Message)"
} finally {
    Write-Host "Selesai."
}

# === Pipeline Processing ===
Get-ChildItem -Recurse -File |
    Where-Object { $_.Length -gt 1MB } |
    Sort-Object Length -Descending |
    Select-Object Name, @{N='SizeMB';E={[math]::Round($_.Length/1MB,2)}} |
    Format-Table -AutoSize
